const token = 'WB_API_TOKEN_PLACEHOLDER';
const headers = { Authorization: token };

const positionByNmId = {};

try {
  const countRes = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://advert-api.wildberries.ru/adv/v1/promotion/count',
    headers,
    json: true
  });
  const advertIds = [];
  for (const g of (countRes?.adverts || [])) {
    for (const a of (g?.advert_list || g?.advertList || [])) {
      if (a?.advertId ?? a?.advert_id) advertIds.push(a.advertId ?? a.advert_id);
