const nmIds = $('Code Parse Cards SuperSale').first().json.nmIds || [];

const fbCounts = {};
const qCounts = {};

const token = 'WB_API_TOKEN_PLACEHOLDER';
const headers = { Authorization: token };

async function contentApi(body) {
  return this.helpers.httpRequest({
    method: 'POST',
    url: 'https://content-api.wildberries.ru/content/v2/get/cards/list',
    headers: { ...headers, 'Content-Type': 'application/json' },
    body,
    json: true
  });
}

async function fetchFeedbacks(nmId) {
  let total = 0;
  try {
    const resAnswered = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://feedbacks-api.wildberries.ru/api/v1/feedbacks',
      qs: { nmId, take: 5000, skip: 0, order: 'dateDesc', isAnswered: true },
      headers,
      json: true
    });
    total += (resAnswered?.data?.feedbacks || []).length;
    await new Promise(r => setTimeout(r, 350));
    const resUnanswered = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://feedbacks-api.wildberries.ru/api/v1/feedbacks',
      qs: { nmId, take: 5000, skip: 0, order: 'dateDesc', isAnswered: false },
      headers,
      json: true
    });
    total += (resUnanswered?.data?.feedbacks || []).length;
    fbCounts[String(nmId)] = total;
  } catch (e) {
    fbCounts[String(nmId)] = fbCounts[String(nmId)] || 0;
  }
}

const imtIdToNmIds = {};
const imtIdQuestionsCache = {};

for (const raw of nmIds) {
  const nmId = Number(raw) || raw;
  await fetchFeedbacks(nmId);
  try {
    const cardRes = await contentApi.call(this, { settings: { cursor: { limit: 100 }, filter: { textSearch: String(nmId), withPhoto: -1 } } });
    const card = (cardRes?.cards || [])[0];
    const imtId = card?.imtID;
    if (!imtId) { qCounts[String(nmId)] = 0; continue; }
    if (!imtIdToNmIds[imtId]) {
      const groupRes = await contentApi.call(this, { settings: { cursor: { limit: 100 }, filter: { imtID: imtId, withPhoto: -1 } } });
      imtIdToNmIds[imtId] = (groupRes?.cards || []).map(c => c.nmID).filter(Boolean);
      await new Promise(r => setTimeout(r, 400));
    }
    if (!(imtId in imtIdQuestionsCache)) {
      let sum = 0;
      for (const nid of imtIdToNmIds[imtId]) {
        try {
          const r = await this.helpers.httpRequest({ method: 'GET', url: 'https://feedbacks-api.wildberries.ru/api/v1/questions/count', qs: { nmId: nid }, headers, json: true });
          sum += Number(r?.data) ?? 0;
          await new Promise(r2 => setTimeout(r2, 350));
        } catch (_) {}
      }
      imtIdQuestionsCache[imtId] = sum;
    }
    qCounts[String(nmId)] = imtIdQuestionsCache[imtId];
  } catch (e) {
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', url: 'https://feedbacks-api.wildberries.ru/api/v1/questions/count', qs: { nmId }, headers, json: true });
