function buildAnalyticsMap(resp) {
  const out = new Map();
  const root = resp || {};
  const products = root.data?.products || root.products || [];
  for (const item of products) {
    const product = item.product || {};
    const statRoot = item.statistic || {};
    const stat = statRoot.selected || statRoot.current || statRoot || {};
    const nmId = String(product.nmId ?? item.nmId ?? '').trim();
    if (!nmId) continue;
    const stocks = product.stocks || {};
    const stockFromAnalytics = Number(stocks.wb) || 0;
    out.set(nmId, {
      orderSum: Number(stat.orderSum) || 0,
      orderCount: Number(stat.orderCount) || 0,
      cartCount: Number(stat.cartCount) || 0,
      openCount: Number(stat.openCount) || 0,
      stockFromAnalytics
    });
  }
  return out;
}

function buildStockMap(stocksItems) {
  const map = new Map();
  for (const item of stocksItems) {
    let data = item?.json ?? item?.body ?? item;
    if (typeof data === 'string') try { data = JSON.parse(data); } catch (_) { data = null; }
    if (data && typeof data === 'object' && !Array.isArray(data)) {
      data = data.data ?? data.result ?? data.items ?? data.stocks ?? [data];
    }
    const rows = Array.isArray(data) ? data : (data && typeof data === 'object' ? [data] : []);
    for (const row of rows) {
      const nmId = String(row?.nmId ?? row?.nm_id ?? '').trim();
      if (!nmId) continue;
      const q = Number(row.quantity ?? row.quantityFull ?? 0) || Number(row.quantityFull ?? 0) || 0;
      map.set(nmId, (map.get(nmId) || 0) + q);
    }
  }
  return map;
}

