} catch (e) {}

const analyticsMap = buildAnalyticsMap(analyticsResp);

const items = [];
for (const card of cards) {
  const nmIdKey = String(card.nmId ?? '').trim();
  const a = analyticsMap.get(nmIdKey) || {};
  const stockFromStats = stockMap.get(nmIdKey) ?? stockMap.get(String(Number(nmIdKey))) ?? null;
  const stock = stockFromStats !== null ? stockFromStats : (a.stockFromAnalytics ?? 0);
  const metrics = {
    orderSum: a.orderSum || 0,
    orderCount: a.orderCount || 0,
    cartCount: a.cartCount || 0,
    openCount: a.openCount || 0,
    stock,
    feedbacksCount: fbCounts[nmIdKey] ?? 0,
    questionsCount: qCounts[nmIdKey] ?? 0,
    searchPosition: positionByNmId[nmIdKey] ?? positionByNmId[String(Number(nmIdKey))] ?? null
  };
  items.push({ json: {
    sheet: 'Новинки_ВБ_фитсмайл_февраль_26 (копия)',
    nmId: nmIdKey,
    rowStart: card.rowStart,
    metrics
  }});
}

return items;

function colLetter(index) {
  let letter = '';
  let n = index;
  while (n >= 0) {
    letter = String.fromCharCode((n % 26) + 65) + letter;
    n = Math.floor(n / 26) - 1;
  }
  return letter;
}

// Merge отдаёт все items от SuperSale + FitSmile
const items = $input.all();
const dates = $('Code Dates').first().json;
// day = день месяца для вчерашней даты (25, если сегодня 26)
const day = Number(dates.day) || 1;
// В таблице 1/2 находится в колонке G, значит базовый индекс = 6 (0-based)
const colIndex = 6 + (day - 1);
const col = colLetter(colIndex);

const data = [];

for (const item of items) {
  const j = item.json || {};
  const sheet = j.sheet;
  const rowStart = Number(j.rowStart);
  const m = j.metrics || {};
  if (!sheet || !rowStart) continue;

  const add = (offset, value) => {
    if (value === undefined || value === null || value === '') return;
    const row = rowStart + offset;
    data.push({
      range: `'${sheet}'!${col}${row}`,
      values: [[value]]
    });
  };

  add(0, m.orderSum);
  add(2, m.orderCount);
  add(3, m.cartCount);
  add(4, m.openCount);
  add(5, m.stock);
  add(7, m.feedbacksCount);
  add(8, m.questionsCount);
  add(9, m.searchPosition);
}

return [{ json: { data } }];
